 1→import { execSync } from 'child_process';
 2→import fs from 'fs';
 3→import path from 'path';
 4→import { fileURLToPath } from 'url';
 5→
 6→const __filename = fileURLToPath(import.meta.url);
 7→const __dirname = path.dirname(__filename);
 8→
 9→// Paths to the files containing the version
10→const packageJsonPath = path.resolve(__dirname, '../package.json');
11→const manifestJsonPath = path.resolve(__dirname, '../manifest.json');
12→const manifestDevJsonPath = path.resolve(__dirname, '../manifest.dev.json');
13→
14→// Helper to read JSON file
15→function readJson(filePath) {
16→  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
17→}
18→
19→// Helper to write JSON file
20→function writeJson(filePath, data) {
21→  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n');
22→}
23→
24→// Logic to bump version with rollover at 10
25→function bumpVersion(version) {
26→  let [major, minor, patch] = version.split('.').map(Number);
27→
28→  patch += 1;
29→
30→  if (patch > 9) {
31→    patch = 0;
32→    minor += 1;
33→  }
34→
35→  if (minor > 9) {
36→    minor = 0;
37→    major += 1;
38→  }
39→
40→  return `${major}.${minor}.${patch}`;
41→}
42→
43→async function main() {
44→  try {
45→    console.log('Reading current version...');
46→    const packageJson = readJson(packageJsonPath);
47→    const currentVersion = packageJson.version;
48→
49→    console.log(`Current version: ${currentVersion}`);
50→
51→    const newVersion = bumpVersion(currentVersion);
52→    console.log(`New version:     ${newVersion}`);
53→
54→    // Update package.json
55→    packageJson.version = newVersion;
56→    writeJson(packageJsonPath, packageJson);
57→    console.log('Updated package.json');
58→
59→    // Update manifest.json
60→    if (fs.existsSync(manifestJsonPath)) {
61→      const manifestJson = readJson(manifestJsonPath);
62→      manifestJson.version = newVersion;
63→      writeJson(manifestJsonPath, manifestJson);
64→      console.log('Updated manifest.json');
65→    } else {
66→      console.warn('manifest.json not found, skipping...');
67→    }
68→
69→    // Update manifest.dev.json
70→    if (fs.existsSync(manifestDevJsonPath)) {
71→      const manifestDevJson = readJson(manifestDevJsonPath);
72→      manifestDevJson.version = newVersion;
73→      writeJson(manifestDevJsonPath, manifestDevJson);
74→      console.log('Updated manifest.dev.json');
75→    }
76→
77→    console.log('Version bump complete! 🚀');
78→
79→    console.log('Running format...');
80→    execSync('bun run format', { stdio: 'inherit' });
81→    console.log('Format complete! ✨');
82→  } catch (error) {
83→    console.error('Error bumping version:', error);
84→    process.exit(1);
85→  }
86→}
87→
88→main();
