 1→import { ManifestV3Export, crx } from '@crxjs/vite-plugin';
 2→import { resolve } from 'path';
 3→import { defineConfig, mergeConfig } from 'vite';
 4→
 5→import baseConfig, { baseBuildOptions, baseManifest } from './vite.config.base';
 6→
 7→const outDir = resolve(__dirname, 'dist_safari');
 8→
 9→// Environment variable to control Safari update check
10→// Set to 'true' to enable update reminders for Safari builds
11→// Default: 'false' (disabled)
12→const enableSafariUpdateCheck = process.env.ENABLE_SAFARI_UPDATE_CHECK === 'true';
13→
14→export default mergeConfig(
15→  baseConfig,
16→  defineConfig({
17→    define: {
18→      // Inject flag into the build
19→      'import.meta.env.ENABLE_SAFARI_UPDATE_CHECK': JSON.stringify(enableSafariUpdateCheck),
20→    },
21→    plugins: [
22→      crx({
23→        manifest: {
24→          ...baseManifest,
25→          // Safari-specific adjustments
26→          background: {
27→            // Safari supports both service_worker and scripts
28→            // Using scripts for better compatibility
29→            scripts: ['src/pages/background/index.ts'],
30→          },
31→        } as ManifestV3Export,
32→        browser: 'chrome', // Use 'chrome' mode as Safari uses WebKit
33→        contentScripts: {
34→          injectCss: true,
35→        },
36→      }),
37→    ],
38→    build: {
39→      ...baseBuildOptions,
40→      outDir,
41→      // Safari-specific build optimizations
42→      target: 'safari14', // Safari 14+ for better extension support
43→    },
44→  }),
45→);
